// ======================================================
// AGRUPA PACIENTES PELO NOME
// RETORNA QUANTIDADE DE EXAMES E LISTA DE EXAMES
// ======================================================

const itens = $input.all().map(item => item.json);

function normalizarTexto(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/\s+/g, " ")
    .trim();
}

const mapaPacientes = new Map();

for (const item of itens) {
  const pacienteOriginal = String(item.Paciente || "").trim();

  if (!pacienteOriginal) continue;

  const chavePaciente = normalizarTexto(pacienteOriginal);

  const exame = String(item.Exame || "").trim();

  if (!mapaPacientes.has(chavePaciente)) {
    mapaPacientes.set(chavePaciente, {
      nomeRelatorio: item.nomeRelatorio || "",
      dataRelatorio: item.dataRelatorio || "",
      dataCadastro: item.dataCadastro || "",
      Paciente: pacienteOriginal,
      pacienteNormalizado: chavePaciente,
      exames: [],
      linhasOriginais: [],
      registros: []
    });
  }

  const paciente = mapaPacientes.get(chavePaciente);

  if (exame) {
    paciente.exames.push(exame);
  }

  paciente.linhasOriginais.push(item.row_number_original || item.row_number || "");

  paciente.registros.push(item);
}

const resultado = [];

for (const paciente of mapaPacientes.values()) {
  resultado.push({
    json: {
      nomeRelatorio: paciente.nomeRelatorio,
      dataRelatorio: paciente.dataRelatorio,
      dataCadastro: paciente.dataCadastro,

      Paciente: paciente.Paciente,
      pacienteNormalizado: paciente.pacienteNormalizado,

      quantidadeExames: paciente.exames.length,
      exames: paciente.exames,
      examesTexto: paciente.exames.join(", "),

      linhasOriginais: paciente.linhasOriginais,

      registros: paciente.registros
    }
  });
}

return resultado;

// ======================================================
// AJUSTA CABEÇALHO PELA LINHA 6
// DESCARTA LINHAS ANTERIORES
// ADICIONA nomeRelatorio, dataRelatorio e dataCadastro
// REMOVE ZERO À ESQUERDA DE "Convênio Sigla"
// ======================================================

const itens = $input.all().map(item => item.json);

// Nome vindo do nó If
// Exemplo: relConvDetalhadoPorLinha_13_05_2026
const nomeArquivo = $('If').first().json.name || "";

// ======================================================
// EXTRAI nomeRelatorio E dataRelatorio
// ======================================================

function extrairInfoRelatorio(nome) {
  const texto = String(nome || "").trim();

  // Aceita:
  // relConvDetalhadoPorLinha_13_05_2026
  // relatorio por linha bipado worklab 16-05-2026
  // relatorio por linha bipado worklab 16_05_2026
  // relatorio por linha bipado worklab 16/05/2026
  const match = texto.match(/^(.+?)[\s_-]+(\d{2})[\/_-](\d{2})[\/_-](\d{4})$/);

  if (!match) {
    return {
      nomeRelatorio: texto,
      dataRelatorio: ""
    };
  }

  return {
    nomeRelatorio: match[1].trim(),
    dataRelatorio: `${match[2]}/${match[3]}/${match[4]}`
  };
}
// ======================================================
// EXTRAI APENAS A DATA
// Exemplo: "12/05/2026 06:01" -> "12/05/2026"
// ======================================================

function extrairDataCadastro(valor) {
  const texto = String(valor || "").trim();
  const match = texto.match(/\b\d{2}\/\d{2}\/\d{4}\b/);
  return match ? match[0] : "";
}

// ======================================================
// REMOVE ZERO À ESQUERDA
// Exemplo: "098" -> "98"
// Exemplo: "012" -> "12"
// Exemplo: "150" -> "150"
// ======================================================

function removerZeroEsquerda(valor) {
  const texto = String(valor ?? "").trim();

  if (!texto) return "";

  const semZeros = texto.replace(/^0+/, "");

  return semZeros || "0";
}

const { nomeRelatorio, dataRelatorio } = extrairInfoRelatorio(nomeArquivo);

// ======================================================
// LOCALIZA A LINHA 6, QUE SERÁ O CABEÇALHO
// ======================================================

const linhaCabecalho = itens.find(item => Number(item.row_number) === 6);

if (!linhaCabecalho) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Linha 6 não encontrada para montar o cabeçalho",
        nomeArquivo,
        nomeRelatorio,
        dataRelatorio
      }
    }
  ];
}

// ======================================================
// MONTA MAPA DAS COLUNAS ORIGINAIS PARA OS NOVOS NOMES
// ======================================================

const mapaCabecalho = {};

for (const [chaveOriginal, valorCabecalho] of Object.entries(linhaCabecalho)) {
  if (chaveOriginal === "row_number") continue;

  const nomeColuna = String(valorCabecalho || "").trim();

  if (!nomeColuna) continue;

  mapaCabecalho[chaveOriginal] = nomeColuna;
}

// ======================================================
// FILTRA APENAS LINHAS APÓS A LINHA 6
// ======================================================

const linhasDados = itens.filter(item => Number(item.row_number) > 6);

// ======================================================
// CONVERTE CADA LINHA USANDO O CABEÇALHO
// ======================================================

const resultado = linhasDados.map(item => {
  const dataCadastro = extrairDataCadastro(
    item["Relatório Paciente por Convênio Detalhado"]
  );

  const novoJson = {
    nomeRelatorio,
    dataRelatorio,
    dataCadastro,
    row_number_original: item.row_number
  };

  for (const [chaveOriginal, nomeColuna] of Object.entries(mapaCabecalho)) {
    let valor = item[chaveOriginal] ?? "";

    // Remove zero à esquerda apenas da coluna Convênio Sigla
    if (nomeColuna === "Convênio Sigla") {
      valor = removerZeroEsquerda(valor);
    }

    novoJson[nomeColuna] = valor;
  }

  return {
    json: novoJson
  };
});

return resultado;

// ======================================================
// ADICIONA ORIGEM AO INPUT 1
// Use este code depois do nó agruparNome-W
// ======================================================

const itens = $input.all();

return itens.map(item => {
  return {
    json: {
      ...item.json,
      origem: "worklab"
    }
  };
});

// ======================================================
// COMPARAR PACIENTES
// ✅ Retorna SOMENTE os itens do INPUT1 que NÃO deram match com INPUT2
// INPUT1: $('Code in JavaScript2').all()
// INPUT2: $('Code in JavaScript10').all()
// Chave: Paciente
// ======================================================

// ======================================================
// NORMALIZA NOME
// Exemplo:
// "JOSÉ HENRIQUE DA COSTA" -> "JOSE HENRIQUE DA COSTA"
// " Jessica  Carvalho " -> "JESSICA CARVALHO"
// ======================================================
function normalizarNome(valor) {
  return String(valor ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase();
}

// ======================================================
// PEGA OS DADOS DOS DOIS NÓS
// ======================================================
const input1 = $('Code in JavaScript2').all().map(item => item.json);
const input2 = $('Code in JavaScript10').all().map(item => item.json);

// ======================================================
// MONTA SET COM OS PACIENTES DO INPUT2
// ======================================================
const pacientesInput2 = new Set();

for (const item2 of input2) {
  const paciente2 = normalizarNome(
    item2.Paciente || item2.pacienteNormalizado || ""
  );

  if (paciente2) {
    pacientesInput2.add(paciente2);
  }
}

// ======================================================
// COMPARA INPUT1 CONTRA INPUT2
// ======================================================
const output = [];

for (const item1 of input1) {
  const pacienteOriginalInput1 = item1.Paciente || "";
  const pacienteNormalizadoInput1 = normalizarNome(
    item1.Paciente || item1.pacienteNormalizado || ""
  );

  if (!pacienteNormalizadoInput1) continue;

  const teveMatch = pacientesInput2.has(pacienteNormalizadoInput1);

  if (!teveMatch) {
    output.push({
      json: {
        teveMatch: false,
        motivo: "Paciente existe no INPUT1, mas não foi encontrado no INPUT2",

        chaveMatch: pacienteNormalizadoInput1,

        input1_Paciente: pacienteOriginalInput1,
        input1_pacienteNormalizado: pacienteNormalizadoInput1,

        input2_Paciente: "",
        input2_pacienteNormalizado: "",

        ...item1
      }
    });
  }
}

// ======================================================
// SE TODOS DERAM MATCH
// ======================================================
if (output.length === 0) {
  return [
    {
      json: {
        teveMatch: true,
        mensagem: "Todos os pacientes do INPUT1 deram match com o INPUT2",
        totalInput1: input1.length,
        totalInput2: input2.length,
        totalSemMatch: 0
      }
    }
  ];
}

// ======================================================
// RETORNA SOMENTE OS SEM MATCH
// ======================================================
return output;

// ======================================================
// AGRUPAR AMOSTRAS POR PACIENTE
// Lê texto OCR do relatório Portal-eDB_RequisicoesEnviadas
// Retorna JSON agrupado por Paciente
// ======================================================

// Altere para false se quiser 1 item por paciente no n8n
const RETORNAR_ARRAY_EM_UM_ITEM = true;

// ======================================================
// 1. PEGA TEXTO DO INPUT
// ======================================================
const input = $input.first().json;

const texto = String(
  input.extractedText ||
  input.text ||
  input.markdown ||
  input.ocr ||
  input.conteudo ||
  ""
);

if (!texto.trim()) {
  return [
    {
      json: {
        erro: true,
        mensagem: "Nenhum texto OCR encontrado. Verifique se o campo é extractedText, text, markdown, ocr ou conteudo."
      }
    }
  ];
}

// ======================================================
// 2. FUNÇÕES AUXILIARES
// ======================================================
function limpar(valor) {
  return String(valor ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizar(valor) {
  return limpar(valor)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase();
}

function limparAgrupamento(valor) {
  return limpar(valor)
    .replace(/REFRIGERAÇÃO/gi, "REFRIGERADO")
    .replace(/REFRIGERACAO/gi, "REFRIGERADO")
    .replace(/\bPLA\s*SMA\b/gi, "PLASMA")
    .replace(/\bSA\s*NGUE\b/gi, "SANGUE")
    .replace(/\s*-\s*/g, " - ")
    .replace(/\s+/g, " ")
    .trim();
}

function ehLinhaIgnorada(linha) {
  const n = normalizar(linha);

  if (!n) return true;
  if (n.includes("---")) return true;
  if (n.includes("OBSERVACAO")) return true;
  if (n.includes("TOTAL DE AMOSTRAS")) return true;
  if (n.includes("TOTAL DE LOTES")) return true;
  if (n.includes("TOTAL DE PACIENTES")) return true;
  if (n.includes("AMOSTRA") && n.includes("MATERIAL") && n.includes("PACIENTE")) return true;
  if (n.includes("CODIGO DO LOTE")) return true;
  if (n.includes("PORTAL-EDB")) return true;
  if (n.includes("ESTE RELATORIO FOI GERADO")) return true;
  if (n.includes("PAGINA")) return true;
  if (n.includes("DB DIAGNOSTICOS")) return true;
  if (n.includes("DB MOLECULAR")) return true;
  if (n.includes("DB PATOLOGIA")) return true;
  if (n.includes("DB TOXICOLOGICO")) return true;

  return false;
}

function extrairColunasTabela(linha) {
  return linha
    .split("|")
    .map(v => limpar(v))
    .filter(v => v !== "");
}

function pareceCodigoLote(valor) {
  return /^REC-\d+$/i.test(limpar(valor));
}

function pareceAmostra(valor) {
  return /^\d{10,15}$/.test(limpar(valor));
}

function pareceDataBR(valor) {
  return /\b\d{2}\/\d{2}\/\d{4}\b/.test(String(valor ?? ""));
}

function extrairDataBR(valor) {
  const m = String(valor ?? "").match(/\b\d{2}\/\d{2}\/\d{4}\b/);
  return m ? m[0] : "";
}

// ======================================================
// 3. PREPARA LINHAS
// ======================================================
const linhas = texto
  .split(/\r?\n/)
  .map(l => limpar(l))
  .filter(l => l);

// ======================================================
// 4. PERCORRE LINHAS E MONTA AGRUPAMENTO POR PACIENTE
// ======================================================
const pacientesMap = new Map();

let loteAtual = {
  codigoLote: "",
  destino: "",
  agrupamento: "",
  acond: "",
  dtCriacao: ""
};

for (const linhaOriginal of linhas) {
  const linha = limpar(linhaOriginal);

  if (!linha.includes("|")) continue;

  const cols = extrairColunasTabela(linha);

  if (cols.length === 0) continue;

  // ====================================================
  // IDENTIFICA LINHA DE LOTE
  // Exemplos:
  // | REC-2156987 | REC | REFRIGERADO - SORO/PLASMA | R | 16/05/2026 |
  // ====================================================
  const idxLote = cols.findIndex(c => pareceCodigoLote(c));

  if (idxLote !== -1) {
    const codigoLote = cols[idxLote] || "";
    const destino = cols[idxLote + 1] || "";
    const agrupamento = cols[idxLote + 2] || "";
    const acond = cols[idxLote + 3] || "";

    let dtCriacao = "";

    for (const c of cols) {
      if (pareceDataBR(c)) {
        dtCriacao = extrairDataBR(c);
        break;
      }
    }

    loteAtual = {
      codigoLote: limpar(codigoLote),
      destino: limpar(destino),
      agrupamento: limparAgrupamento(agrupamento),
      acond: limpar(acond),
      dtCriacao: limpar(dtCriacao)
    };

    continue;
  }

  if (ehLinhaIgnorada(linha)) continue;

  // ====================================================
  // IDENTIFICA LINHA DE AMOSTRA
  // Exemplo:
  // | 140773041701 | SORO | ALEXSANDRO DOS SANTOS PEREIRA | | TBAMAR |
  // ====================================================
  const idxAmostra = cols.findIndex(c => pareceAmostra(c));

  if (idxAmostra === -1) continue;

  const amostra = cols[idxAmostra] || "";
  const material = cols[idxAmostra + 1] || "";
  const paciente = cols[idxAmostra + 2] || "";
  const meioColeta = cols[idxAmostra + 3] || "";

  if (!amostra || !material || !paciente) continue;

  const nomePaciente = limpar(paciente).toUpperCase();

  if (!pacientesMap.has(nomePaciente)) {
    pacientesMap.set(nomePaciente, {
      Paciente: nomePaciente,
      dtCriacao: loteAtual.dtCriacao || "",
      qtAmostras: 0,
      amostras: []
    });
  }

  const registroPaciente = pacientesMap.get(nomePaciente);

  // Se ainda não tinha data, usa a data do lote atual
  if (!registroPaciente.dtCriacao && loteAtual.dtCriacao) {
    registroPaciente.dtCriacao = loteAtual.dtCriacao;
  }

  registroPaciente.amostras.push({
    Amostra: limpar(amostra),
    Material: limpar(material),
    "Meio de Coleta": limpar(meioColeta),
    "Codigo do Lote": loteAtual.codigoLote || "",
    Destino: loteAtual.destino || "",
    Agrupamento: loteAtual.agrupamento || "",
    acond: loteAtual.acond || ""
  });

  registroPaciente.qtAmostras = registroPaciente.amostras.length;
}

// ======================================================
// 5. MONTA RESULTADO FINAL ORDENADO POR NOME
// ======================================================
const resultado = Array.from(pacientesMap.values())
  .sort((a, b) => a.Paciente.localeCompare(b.Paciente, "pt-BR"));

// ======================================================
// 6. RETORNO
// ======================================================
if (resultado.length === 0) {
  return [
    {
      json: {
        erro: true,
        mensagem: "Nenhuma amostra foi encontrada no texto OCR.",
        totalPacientes: 0,
        dados: []
      }
    }
  ];
}

// Retorna tudo dentro de um único item
if (RETORNAR_ARRAY_EM_UM_ITEM) {
  return [
    {
      json: {
        sucesso: true,
        totalPacientes: resultado.length,
        dados: resultado
      }
    }
  ];
}

// Retorna 1 item por paciente
return resultado.map((paciente, index) => ({
  json: {
    sucesso: true,
    _idx: index + 1,
    _totalPacientes: resultado.length,
    ...paciente
  }
}));

// ======================================================
// EXPLODIR ARRAY DE AMOSTRAS POR PACIENTE
// ✅ Entrada esperada:
// {
//   sucesso: true,
//   totalPacientes: 182,
//   dados: [
//     {
//       Paciente: "...",
//       dtCriacao: "...",
//       qtAmostras: 2,
//       amostras: [{...}, {...}]
//     }
//   ]
// }
//
// ✅ Saída:
// 1 item por amostra
// mantendo:
// - Paciente
// - dtCriacao
// - qtAmostras
// - amostrasUnica
// - amostras completo
// ======================================================

const inputItems = $input.all();

const output = [];

function isObjeto(valor) {
  return valor && typeof valor === "object" && !Array.isArray(valor);
}

function processarPaciente(paciente) {
  if (!isObjeto(paciente)) return;

  const amostras = Array.isArray(paciente.amostras)
    ? paciente.amostras
    : [];

  if (amostras.length === 0) {
    output.push({
      json: {
        ...paciente,
        qtAmostras: Number(paciente.qtAmostras || 0),
        amostrasUnica: {},
        amostras: []
      }
    });

    return;
  }

  for (const amostra of amostras) {
    output.push({
      json: {
        Paciente: paciente.Paciente || "",
        dtCriacao: paciente.dtCriacao || "",
        qtAmostras: Number(paciente.qtAmostras || amostras.length),

        amostrasUnica: {
          ...amostra
        },

        amostras: amostras
      }
    });
  }
}

// ======================================================
// SUPORTA 3 FORMATOS DE ENTRADA
// ======================================================

for (const item of inputItems) {
  const json = item.json || {};

  // Formato 1:
  // { dados: [paciente1, paciente2] }
  if (Array.isArray(json.dados)) {
    for (const paciente of json.dados) {
      processarPaciente(paciente);
    }

    continue;
  }

  // Formato 2:
  // [paciente1, paciente2] vindo dentro de json
  if (Array.isArray(json)) {
    for (const paciente of json) {
      processarPaciente(paciente);
    }

    continue;
  }

  // Formato 3:
  // Cada item já é um paciente individual
  if (json.Paciente && Array.isArray(json.amostras)) {
    processarPaciente(json);
  }
}

// ======================================================
// RETORNO CASO NÃO ENCONTRE NADA
// ======================================================

if (output.length === 0) {
  return [
    {
      json: {
        erro: true,
        mensagem: "Nenhum paciente com array de amostras foi encontrado para explodir."
      }
    }
  ];
}

return output;

// ======================================================
// EXPLODIR ARRAY "dados"
// ✅ Entrada:
// {
//   sucesso: true,
//   totalPacientes: 182,
//   dados: [
//     { Paciente: "...", dtCriacao: "...", qtAmostras: ..., amostras: [...] }
//   ]
// }
//
// ✅ Saída:
// 1 item por paciente
// ======================================================

const input = $input.first().json;

const dados = Array.isArray(input.dados) ? input.dados : [];

if (dados.length === 0) {
  return [
    {
      json: {
        erro: true,
        mensagem: "A chave 'dados' não existe ou está vazia.",
        totalPacientes: 0
      }
    }
  ];
}

return dados.map((paciente, index) => {
  return {
    json: {
      _idx: index + 1,
      _totalPacientes: dados.length,

      sucesso: input.sucesso ?? true,
      totalPacientes: input.totalPacientes ?? dados.length,

      ...paciente
    }
  };
});

// ======================================================
// MONTA MENSAGENS PARA WHATSAPP
// ✅ Entrada: itens com paciente, exames e registros
// ✅ Saída: 1 item por paciente com mensagem pronta
// ======================================================

const itens = $input.all();

function valorSeguro(valor, padrao = "") {
  if (valor === null || valor === undefined) return padrao;
  return String(valor).trim();
}

function formatarExames(exames) {
  if (Array.isArray(exames)) {
    return exames
      .map(e => String(e).trim())
      .filter(e => e)
      .join(", ");
  }

  if (typeof exames === "string") {
    return exames.trim();
  }

  return "";
}

const mensagens = [];

for (const item of itens) {
  const json = item.json || {};

  const primeiroRegistro = Array.isArray(json.registros) && json.registros.length > 0
    ? json.registros[0]
    : {};

  const dataCadastro = valorSeguro(
    primeiroRegistro.dataCadastro || json.dataCadastro
  );

  const paciente = valorSeguro(
    json.input1_Paciente || json.Paciente
  );

  const examesTexto = formatarExames(json.exames || json.examesTexto);

  const convenioSigla = valorSeguro(
    primeiroRegistro["Convênio Sigla"] || json["Convênio Sigla"]
  );

  const quantidadeExames = Number(
    json.quantidadeExames || 
    json.qtExames || 
    (Array.isArray(json.exames) ? json.exames.length : 0)
  );

  const mensagem =
`⚠️ *Paciente não encontrado no relatório do DB*

📅 *Data:* ${dataCadastro}
👤 *Paciente:* ${paciente}
🏥 *Convênio:* ${convenioSigla}
🧪 *Quantidade de exames:* ${quantidadeExames}
📋 *Exames:* ${examesTexto}`;

  mensagens.push({
    json: {
      dataCadastro,
      Paciente: paciente,
      exames: Array.isArray(json.exames) ? json.exames : [],
      examesTexto,
      convenioSigla,
      quantidadeExames,
      mensagemWhatsApp: mensagem
    }
  });
}

if (mensagens.length === 0) {
  return [
    {
      json: {
        erro: true,
        mensagem: "Nenhum item encontrado para montar mensagem de WhatsApp."
      }
    }
  ];
}

return mensagens;

// ======================================================
// AGRUPA PACIENTES PELO NOME
// RETORNA QUANTIDADE DE EXAMES E LISTA DE EXAMES
// ======================================================

const itens = $input.all().map(item => item.json);

function normalizarTexto(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/\s+/g, " ")
    .trim();
}

const mapaPacientes = new Map();

for (const item of itens) {
  const pacienteOriginal = String(item.Paciente || "").trim();

  if (!pacienteOriginal) continue;

  const chavePaciente = normalizarTexto(pacienteOriginal);

  const exame = String(item.Exame || "").trim();

  if (!mapaPacientes.has(chavePaciente)) {
    mapaPacientes.set(chavePaciente, {
      nomeRelatorio: item.nomeRelatorio || "",
      dataRelatorio: item.dataRelatorio || "",
      dataCadastro: item.dataCadastro || "",
      Paciente: pacienteOriginal,
      pacienteNormalizado: chavePaciente,
      exames: [],
      linhasOriginais: [],
      registros: []
    });
  }

